def find_optimal_set(n):
    # Enumerate all possible sets of coins
    coin_sets = [list(combination) for combination in itertools.combinations(range(1, 2*n+1), n)]

    # Calculate the probability of getting n heads for each set
    probabilities = []
    for coin_set in coin_sets:
        probability = 0
        for configuration in itertools.product([0, 1], repeat=n):
            probability_configuration = 1
            for i, coin in enumerate(coin_set):
                if configuration[i] == 0:
                    probability_configuration *= (coin - 1) / (2*coin - 1)
                else:
                    probability_configuration *= (2*coin - 2) / (2*coin - 1)
            probability += probability_configuration
        probabilities.append(probability)

    # Find the set with the highest probability
    optimal_set = coin_sets[probabilities.index(max(probabilities))]
    return optimal_set

