def solve_coin_problem(p_values):
    n = len(p_values) // 2
    best_subset = None
    best_probability = 0

    for subset in combinations(p_values, n):
        subset_sum = sum(subset)
        probability = np.sum([np.math.comb(n, i) * (subset_sum / n) ** i * (1 - subset_sum / n) ** (n - i) for i in range(n, n + 1)])
        if probability > best_probability:
            best_subset = subset
            best_probability = probability

    return best_subset

