def recursive(n, coins=None, current_sum=0, index=0):
    if coins is None:
        coins = [2 ** i for i in range(n)]
    if current_sum == n:
        return [1 if i < index else 0 for i in range(len(coins))]
    if current_sum > n or index == len(coins):
        return None
    result = recursive(n, coins, current_sum + coins[index], index + 1)
    if result is not None:
        return result
    return recursive(n, coins, current_sum, index + 1)

